SELECT AVG(Age) AS Average_Age, MIN(Age) AS Minimum_Age, MAX(Age) AS Maximum_Age 
FROM singer 
WHERE Country = 'France';

SELECT COUNT(*) 
FROM concert 
WHERE Stadium_ID = (SELECT Stadium_ID FROM stadium ORDER BY Capacity DESC LIMIT 1);

SELECT Song_Name, Song_release_year 
FROM singer 
WHERE Age = (SELECT MIN(Age) FROM singer);

SELECT Country, COUNT(Singer_ID) AS Number_of_Singers
FROM singer
GROUP BY Country;

SELECT COUNT(*) 
FROM Has_Pet 
WHERE StuID IN (SELECT StuID FROM Student WHERE Age > 20);

SELECT PetType, AVG(pet_age) AS average_age, MAX(pet_age) AS maximum_age
FROM Pets
GROUP BY PetType;

SELECT Has_Pet.StuID, COUNT(Has_Pet.PetID) AS NumberOfPets
FROM Has_Pet
GROUP BY Has_Pet.StuID;

SELECT PetType, MAX(weight) AS max_weight
FROM Pets
GROUP BY PetType;
